//! Entity gazetteer: a sovereign topical model over ~14M cleaned, case-insensitive
//! Wikipedia titles — the "topics knot".
//!
//! Every Wikipedia title is cleaned + case-folded into a token sequence, hashed
//! (FNV-1a 64), and indexed. A query (e.g. the content of one of our `.lean` files —
//! the "lean knot") is cleaned the same way, then scanned with sliding 1..=N token
//! windows; a window hit means the query mentions that entity as a contiguous span.
//!
//! Scoring is **idf-weighted** (rare title tokens like `ackermann` beat common ones
//! like `the`/`function`) with **log-damped mention counts** (a token repeated 168×
//! in code does not linearly dominate a precise 2-word entity). Junk titles
//! (pure digits/punctuation, single chars, all-stopword) are dropped at build time.
//! Each match's integer score is the **logit**; per-query logits are normalized to a
//! probability distribution by the in-crate Buleyean god formula
//! (`substrate_bridge::buleyean_load_distribution`) — the sovereign probability engine.
//!
//! Two backends share one scan path via the [`EntityLookup`] trait:
//!   * [`Gazetteer`]   — built in memory from the title file (also writes the knot).
//!   * [`MappedGazetteer`] — `mmap`s a prebuilt `.eknot` from disk: zero rebuild,
//!     RAM only for hot pages (the "disk is just as fast" path).
//!
//! Pure `std` + `memmap2`/`bytemuck` (native only) for the disk knot; no external
//! pattern-matching crate. Parallel scanning is done by the caller via `gnosis-frf`.

use std::collections::HashMap;
use std::collections::HashSet;
use std::fs::File;
use std::io::{BufRead, BufReader, BufWriter, Write};
use std::path::Path;

use crate::substrate_bridge::buleyean_load_distribution;

/// Index into the gazetteer's title arena.
pub type EntityId = u32;

const SEP: u8 = 0x1f;
const FNV_OFFSET: u64 = 0xcbf2_9ce4_8422_2325;
const FNV_PRIME: u64 = 0x0000_0100_0000_01b3;

#[inline]
fn hash_window(tokens: &[&str]) -> u64 {
    let mut h: u64 = FNV_OFFSET;
    for (i, tok) in tokens.iter().enumerate() {
        if i > 0 {
            h ^= SEP as u64;
            h = h.wrapping_mul(FNV_PRIME);
        }
        for &b in tok.as_bytes() {
            h ^= b as u64;
            h = h.wrapping_mul(FNV_PRIME);
        }
    }
    h
}

#[inline]
fn hash_token(tok: &str) -> u64 {
    let mut h: u64 = FNV_OFFSET;
    for &b in tok.as_bytes() {
        h ^= b as u64;
        h = h.wrapping_mul(FNV_PRIME);
    }
    h
}

const STOPWORDS: &[&str] = &[
    "the", "and", "for", "are", "was", "were", "his", "her", "its", "our", "their", "with", "from",
    "that", "this", "than", "then", "into", "onto", "over", "under", "about", "not", "but", "all",
    "any", "can", "had", "has", "have", "who", "whom", "why", "how", "what", "when", "where",
    "which", "you", "your", "they", "them", "she", "him", "out", "off", "per", "via", "vs", "etc",
];

#[inline]
fn is_stopword(tok: &str) -> bool {
    STOPWORDS.contains(&tok)
}

#[inline]
fn is_wordy(tok: &str) -> bool {
    tok.len() >= 3 && tok.bytes().all(|b| b.is_ascii_alphabetic()) && !is_stopword(tok)
}

#[inline]
fn is_useful(tokens: &[String]) -> bool {
    tokens.iter().any(|t| is_wordy(t))
}

/// Clean a raw title/query into lowercase alphanumeric tokens.
pub fn clean_tokens(s: &str) -> Vec<String> {
    let mut out: Vec<String> = Vec::new();
    let mut cur = String::new();
    for ch in s.chars() {
        let c = if ch == '_' { ' ' } else { ch };
        if c.is_ascii_alphanumeric() {
            cur.push(c.to_ascii_lowercase());
        } else if !cur.is_empty() {
            out.push(std::mem::take(&mut cur));
        }
    }
    if !cur.is_empty() {
        out.push(cur);
    }
    out
}

/// A scored entity match.
#[derive(Clone, Debug)]
pub struct EntityHit {
    pub entity: EntityId,
    pub slug: String,
    pub span: u8,
    pub count: u32,
    pub logit: u64,
    pub prob: f64,
}

/// Backend-agnostic gazetteer lookup. Implemented by both the in-memory and the
/// `mmap`'d disk-knot gazetteer so they share one scan/scoring path.
pub trait EntityLookup {
    /// Resolve a cleaned-window hash to an entity id.
    fn lookup(&self, hash: u64) -> Option<EntityId>;
    /// idf specificity for an entity (higher = rarer/more specific).
    fn specificity(&self, id: EntityId) -> f32;
    /// Canonical raw Wikipedia slug for an entity.
    fn slug(&self, id: EntityId) -> &str;
}

/// Scan a query against any [`EntityLookup`] backend, returning top-`top` scored hits.
///
/// logit = best-span-weight × (1 + ln(mention_count)) × idf_specificity, rounded.
pub fn scan_entities<L: EntityLookup + ?Sized>(
    lk: &L,
    query: &str,
    max_ngram: usize,
    top: usize,
) -> Vec<EntityHit> {
    let tokens = clean_tokens(query);
    if tokens.is_empty() {
        return Vec::new();
    }
    let toks: Vec<&str> = tokens.iter().map(|s| s.as_str()).collect();

    // entity -> (best span weight, mention count, best span)
    let mut acc: HashMap<EntityId, (u64, u32, u8)> = HashMap::new();
    let n = toks.len();
    let maxw = max_ngram.max(1);

    for start in 0..n {
        let end_cap = (start + maxw).min(n);
        for end in (start + 1)..=end_cap {
            let window = &toks[start..end];
            let h = hash_window(window);
            if let Some(id) = lk.lookup(h) {
                let span = (end - start) as u8;
                let w: u64 = match span {
                    1 => 1,
                    2 => 6,
                    3 => 18,
                    _ => (span as u64) * (span as u64) * 6,
                };
                let e = acc.entry(id).or_insert((0, 0, 0));
                if w > e.0 {
                    e.0 = w;
                }
                e.1 += 1;
                if span > e.2 {
                    e.2 = span;
                }
            }
        }
    }

    if acc.is_empty() {
        return Vec::new();
    }

    let mut hits: Vec<EntityHit> = acc
        .into_iter()
        .map(|(id, (best_w, count, span))| {
            let spec = lk.specificity(id) as f64;
            let damp = 1.0 + (count as f64).ln();
            let logit = ((best_w as f64) * damp * spec).round() as u64;
            EntityHit {
                entity: id,
                slug: lk.slug(id).to_string(),
                span,
                count,
                logit,
                prob: 0.0,
            }
        })
        .collect();
    hits.sort_by(|a, b| b.logit.cmp(&a.logit).then(a.slug.cmp(&b.slug)));
    hits.truncate(top);

    let max_logit = hits.iter().map(|h| h.logit).max().unwrap_or(0);
    let round: u32 = max_logit.min(u32::MAX as u64) as u32;
    let rejections: Vec<u32> = hits
        .iter()
        .map(|h| (max_logit - h.logit).min(u32::MAX as u64) as u32)
        .collect();
    let dist = buleyean_load_distribution(&rejections, round);
    for (h, p) in hits.iter_mut().zip(dist.into_iter()) {
        h.prob = p;
    }
    hits
}

// ─── In-memory gazetteer ────────────────────────────────────────────────────

/// The in-memory topical model / entity gazetteer.
pub struct Gazetteer {
    map: HashMap<u64, EntityId>,
    arena: String,
    slug_offsets: Vec<u32>,
    token_count: Vec<u8>,
    specificity: Vec<f32>,
}

impl EntityLookup for Gazetteer {
    #[inline]
    fn lookup(&self, hash: u64) -> Option<EntityId> {
        self.map.get(&hash).copied()
    }
    #[inline]
    fn specificity(&self, id: EntityId) -> f32 {
        self.specificity[id as usize]
    }
    #[inline]
    fn slug(&self, id: EntityId) -> &str {
        let start = self.slug_offsets[id as usize] as usize;
        let end = self.slug_offsets[id as usize + 1] as usize;
        &self.arena[start..end]
    }
}

impl Gazetteer {
    pub fn entity_count(&self) -> usize {
        self.token_count.len()
    }

    /// Build the gazetteer by streaming a newline-delimited title file.
    pub fn build_from_file(path: &Path, max_title_tokens: usize) -> std::io::Result<Self> {
        let file = File::open(path)?;
        let reader = BufReader::with_capacity(1 << 20, file);

        let mut map: HashMap<u64, EntityId> = HashMap::with_capacity(16_000_000);
        let mut arena = String::with_capacity(1 << 30);
        let mut slug_offsets: Vec<u32> = Vec::with_capacity(16_000_000);
        let mut token_count: Vec<u8> = Vec::with_capacity(16_000_000);
        let mut df: HashMap<u64, u32> = HashMap::with_capacity(8_000_000);
        slug_offsets.push(0);

        for line in reader.lines() {
            let raw = line?;
            let raw = raw.trim();
            if raw.is_empty() || raw.contains("(disambiguation)") {
                continue;
            }
            let tokens = clean_tokens(raw);
            if tokens.is_empty() || !is_useful(&tokens) {
                continue;
            }
            let span = tokens.len().min(max_title_tokens);
            let toks: Vec<&str> = tokens[..span].iter().map(|s| s.as_str()).collect();
            let h = hash_window(&toks);
            if map.contains_key(&h) {
                continue;
            }

            let id = token_count.len() as EntityId;
            map.insert(h, id);
            arena.push_str(raw);
            slug_offsets.push(arena.len() as u32);
            token_count.push(span as u8);

            let mut seen_tok: HashSet<u64> = HashSet::with_capacity(toks.len());
            for t in &toks {
                let th = hash_token(t);
                if seen_tok.insert(th) {
                    *df.entry(th).or_insert(0) += 1;
                }
            }
        }

        let n = token_count.len().max(1) as f64;
        let mut specificity: Vec<f32> = Vec::with_capacity(token_count.len());
        for id in 0..token_count.len() as EntityId {
            let start = slug_offsets[id as usize] as usize;
            let end = slug_offsets[id as usize + 1] as usize;
            let toks = clean_tokens(&arena[start..end]);
            let mut max_idf = 0.0f32;
            for (i, t) in toks.iter().enumerate() {
                if i >= max_title_tokens {
                    break;
                }
                let th = hash_token(t);
                let dfc = (*df.get(&th).unwrap_or(&1)).max(1) as f64;
                let idf = (n / dfc).ln() as f32;
                let idf = if is_wordy(t) { idf } else { idf * 0.05 };
                if idf > max_idf {
                    max_idf = idf;
                }
            }
            specificity.push(max_idf.max(0.01));
        }

        Ok(Gazetteer {
            map,
            arena,
            slug_offsets,
            token_count,
            specificity,
        })
    }

    /// Serialize to an `.eknot` disk knot (header + sorted hash index + specificity
    /// + slug offsets + slug arena). See [`MappedGazetteer`] for the reader.
    pub fn write_knot(&self, path: &Path) -> std::io::Result<()> {
        let n = self.entity_count();
        let mut index: Vec<KnotIndexEntry> = self
            .map
            .iter()
            .map(|(&hash, &id)| KnotIndexEntry { hash, id, _pad: 0 })
            .collect();
        index.sort_by(|a, b| a.hash.cmp(&b.hash));

        let off_index: u64 = KNOT_HEADER_SIZE as u64;
        let off_spec: u64 =
            off_index + (index.len() * std::mem::size_of::<KnotIndexEntry>()) as u64;
        let off_slugoff: u64 = off_spec + (n * 4) as u64;
        let off_arena: u64 = off_slugoff + ((n + 1) * 4) as u64;

        let header = KnotHeader {
            magic: *KNOT_MAGIC,
            version: 1,
            _pad0: 0,
            n_entities: n as u64,
            arena_len: self.arena.len() as u64,
            off_index,
            off_spec,
            off_slugoff,
            off_arena,
        };

        let file = File::create(path)?;
        let mut w = BufWriter::with_capacity(1 << 20, file);
        w.write_all(bytemuck::bytes_of(&header))?;
        w.write_all(bytemuck::cast_slice(&index))?;
        w.write_all(bytemuck::cast_slice(&self.specificity))?;
        w.write_all(bytemuck::cast_slice(&self.slug_offsets))?;
        w.write_all(self.arena.as_bytes())?;
        w.flush()?;
        Ok(())
    }
}

// ─── Disk knot (.eknot) format ──────────────────────────────────────────────

const KNOT_MAGIC: &[u8; 8] = b"EREAP\0\0\0";
const KNOT_HEADER_SIZE: usize = 64;

#[repr(C)]
#[derive(Clone, Copy, bytemuck::Pod, bytemuck::Zeroable)]
struct KnotHeader {
    magic: [u8; 8],
    version: u32,
    _pad0: u32,
    n_entities: u64,
    arena_len: u64,
    off_index: u64,
    off_spec: u64,
    off_slugoff: u64,
    off_arena: u64,
}

#[repr(C)]
#[derive(Clone, Copy, bytemuck::Pod, bytemuck::Zeroable)]
struct KnotIndexEntry {
    hash: u64,
    id: u32,
    _pad: u32,
}

/// A gazetteer backed by an `mmap`'d `.eknot` file — no in-memory rebuild.
/// Native only (`memmap2` is wasm-incompatible).
#[cfg(not(target_arch = "wasm32"))]
pub struct MappedGazetteer {
    _mmap: memmap2::Mmap,
    n: usize,
    off_index: usize,
    off_spec: usize,
    off_slugoff: usize,
    off_arena: usize,
    arena_len: usize,
    // raw base pointer kept via the mmap; slices recomputed per access (cheap casts).
    bytes: *const u8,
    len: usize,
}

// The mmap is read-only and never mutated after open; safe to share across threads.
#[cfg(not(target_arch = "wasm32"))]
unsafe impl Send for MappedGazetteer {}
#[cfg(not(target_arch = "wasm32"))]
unsafe impl Sync for MappedGazetteer {}

#[cfg(not(target_arch = "wasm32"))]
impl MappedGazetteer {
    pub fn open(path: &Path) -> std::io::Result<Self> {
        let file = File::open(path)?;
        let mmap = unsafe { memmap2::Mmap::map(&file)? };
        if mmap.len() < KNOT_HEADER_SIZE {
            return Err(std::io::Error::new(
                std::io::ErrorKind::InvalidData,
                "eknot too small",
            ));
        }
        let header: KnotHeader = *bytemuck::from_bytes(&mmap[..KNOT_HEADER_SIZE]);
        if &header.magic != KNOT_MAGIC {
            return Err(std::io::Error::new(
                std::io::ErrorKind::InvalidData,
                "bad eknot magic",
            ));
        }
        let bytes = mmap.as_ptr();
        let len = mmap.len();
        Ok(MappedGazetteer {
            _mmap: mmap,
            n: header.n_entities as usize,
            off_index: header.off_index as usize,
            off_spec: header.off_spec as usize,
            off_slugoff: header.off_slugoff as usize,
            off_arena: header.off_arena as usize,
            arena_len: header.arena_len as usize,
            bytes,
            len,
        })
    }

    pub fn entity_count(&self) -> usize {
        self.n
    }

    #[inline]
    fn slice(&self, off: usize, byte_len: usize) -> &[u8] {
        assert!(off + byte_len <= self.len, "eknot section out of bounds");
        unsafe { std::slice::from_raw_parts(self.bytes.add(off), byte_len) }
    }

    #[inline]
    fn index(&self) -> &[KnotIndexEntry] {
        bytemuck::cast_slice(self.slice(
            self.off_index,
            self.n * std::mem::size_of::<KnotIndexEntry>(),
        ))
    }
    #[inline]
    fn spec(&self) -> &[f32] {
        bytemuck::cast_slice(self.slice(self.off_spec, self.n * 4))
    }
    #[inline]
    fn slugoff(&self) -> &[u32] {
        bytemuck::cast_slice(self.slice(self.off_slugoff, (self.n + 1) * 4))
    }
    #[inline]
    fn arena(&self) -> &str {
        let b = self.slice(self.off_arena, self.arena_len);
        // The arena was written from a valid Rust String.
        unsafe { std::str::from_utf8_unchecked(b) }
    }
}

#[cfg(not(target_arch = "wasm32"))]
impl EntityLookup for MappedGazetteer {
    #[inline]
    fn lookup(&self, hash: u64) -> Option<EntityId> {
        let idx = self.index();
        idx.binary_search_by(|e| e.hash.cmp(&hash))
            .ok()
            .map(|pos| idx[pos].id)
    }
    #[inline]
    fn specificity(&self, id: EntityId) -> f32 {
        self.spec()[id as usize]
    }
    #[inline]
    fn slug(&self, id: EntityId) -> &str {
        let offs = self.slugoff();
        let start = offs[id as usize] as usize;
        let end = offs[id as usize + 1] as usize;
        &self.arena()[start..end]
    }
}

/// De-duplicate a set of slugs (used when merging cross-file entity sets).
pub fn unique_slugs(slugs: impl IntoIterator<Item = String>) -> Vec<String> {
    let mut seen = HashSet::new();
    let mut out = Vec::new();
    for s in slugs {
        if seen.insert(s.clone()) {
            out.push(s);
        }
    }
    out
}
